158: 	for _, panel := range panels {
159: 		panelMap, ok := panel.(map[string]interface{})
160: 		if !ok {
161: 			continue
162: 		}
163: 		migratePanelDatasources(panelMap, index)
164: 
165: 		// Handle nested panels in collapsed rows
166: 		nestedPanels, hasNested := panelMap["panels"].([]interface{})
167: 		if !hasNested {
168: 			continue
169: 		}
170: 
171: 		for _, nestedPanel := range nestedPanels {
172: 			np, ok := nestedPanel.(map[string]interface{})
173: 			if !ok {
174: 				continue
175: 			}
176: 			migratePanelDatasourcesInternal(np, index, true)
177: 		}
178: 	}
179: }
