676: // isEqual checks if two values are equal (simplified version)
677: func isEqual(a, b interface{}) bool {
678: 	if a == nil && b == nil {
679: 		return true
680: 	}
681: 	if a == nil || b == nil {
682: 		return false
683: 	}
684: 
685: 	// For simple types, use direct comparison
686: 	switch aVal := a.(type) {
687: 	case bool:
688: 		if bVal, ok := b.(bool); ok {
689: 			return aVal == bVal
690: 		}
691: 	case string:
692: 		if bVal, ok := b.(string); ok {
693: 			return aVal == bVal
694: 		}
695: 	case float64:
696: 		if bVal, ok := b.(float64); ok {
697: 			return aVal == bVal
698: 		}
699: 	case []interface{}:
700: 		if bVal, ok := b.([]interface{}); ok {
701: 			if len(aVal) != len(bVal) {
702: 				return false
703: 			}
704: 			for i, v := range aVal {
705: 				if !isEqual(v, bVal[i]) {
706: 					return false
707: 				}
708: 			}
709: 			return true
710: 		}
711: 	case map[string]interface{}:
712: 		if bVal, ok := b.(map[string]interface{}); ok {
713: 			if len(aVal) != len(bVal) {
714: 				return false
715: 			}
716: 			for k, v := range aVal {
717: 				if !isEqual(v, bVal[k]) {
718: 					return false
719: 				}
720: 			}
721: 			return true
722: 		}
723: 	}
724: 
725: 	return false
726: }
